<template>
	<div>
		<div ref="containerRef" class="relative">
			<nav class="flex relative" :style="{ transform: 'translate3d(0,0,0.01px)' }">
				<ul
					ref="navRef"
					class="flex gap-8 list-none p-0 px-4 m-0 relative z-[3]"
					:style="{
  color: 'white',
  textShadow: '0 1px 1px hsl(205deg 30% 10% / 0.2)'
}"
				>
					<li
						v-for="(item, index) in items"
						:key="index"
						class="rounded-full relative cursor-pointer transition-[background-color_color_box-shadow] duration-300 ease shadow-[0_0_0.5px_1.5px_transparent] text-white" :class="[
  { active: activeIndex === index }
]"
					>
						<NuxtLink
							:to="item.href || void 0"
							class="outline-none py-[0.6em] px-[1em] inline-block"
							@click="(e) => handleClick(e, index)"
							@keydown="(e) => handleKeyDown(e, index)"
						>
							{{ item.label }}
						</NuxtLink>
					</li>
				</ul>
			</nav>

			<span ref="filterRef" class="effect filter" />

			<span ref="textRef" class="effect text" />
		</div>
	</div>
</template>

<script setup>
import { onMounted, onUnmounted, ref, watch } from "vue";
const props = defineProps({
  items: { type: Array, required: true },
  animationTime: { type: Number, required: false, default: 600 },
  particleCount: { type: Number, required: false, default: 15 },
  particleDistances: { type: Array, required: false, default: () => [90, 10] },
  particleR: { type: Number, required: false, default: 100 },
  timeVariance: { type: Number, required: false, default: 300 },
  colors: { type: Array, required: false, default: () => [1, 2, 3, 1, 2, 3, 1, 4] },
  initialActiveIndex: { type: Number, required: false, default: 0 }
});
const containerRef = ref();
const navRef = ref();
const filterRef = ref();
const textRef = ref();
const activeIndex = ref(props.initialActiveIndex);
let resizeObserver = null;
const noise = (n = 1) => n / 2 - Math.random() * n;
const getXY = (distance, pointIndex, totalPoints) => {
  const angle = (360 + noise(8)) / totalPoints * pointIndex * (Math.PI / 180);
  return [distance * Math.cos(angle), distance * Math.sin(angle)];
};
const createParticle = (i, t, d, r) => {
  const rotate = noise(r / 10);
  return {
    start: getXY(d[0], props.particleCount - i, props.particleCount),
    end: getXY(d[1] + noise(7), props.particleCount - i, props.particleCount),
    time: t,
    scale: 1 + noise(0.2),
    color: props.colors[Math.floor(Math.random() * props.colors.length)],
    rotate: rotate > 0 ? (rotate + r / 20) * 10 : (rotate - r / 20) * 10
  };
};
const makeParticles = (element) => {
  const d = props.particleDistances;
  const r = props.particleR;
  const bubbleTime = props.animationTime * 2 + props.timeVariance;
  element.style.setProperty("--time", `${bubbleTime}ms`);
  for (let i = 0; i < props.particleCount; i++) {
    const t = props.animationTime * 2 + noise(props.timeVariance * 2);
    const p = createParticle(i, t, d, r);
    element.classList.remove("active");
    setTimeout(() => {
      const particle = document.createElement("span");
      const point = document.createElement("span");
      particle.classList.add("particle");
      particle.style.setProperty("--start-x", `${p.start[0]}px`);
      particle.style.setProperty("--start-y", `${p.start[1]}px`);
      particle.style.setProperty("--end-x", `${p.end[0]}px`);
      particle.style.setProperty("--end-y", `${p.end[1]}px`);
      particle.style.setProperty("--time", `${p.time}ms`);
      particle.style.setProperty("--scale", `${p.scale}`);
      particle.style.setProperty("--color", `var(--color-${p.color}, white)`);
      particle.style.setProperty("--rotate", `${p.rotate}deg`);
      point.classList.add("point");
      particle.appendChild(point);
      element.appendChild(particle);
      requestAnimationFrame(() => {
        element.classList.add("active");
      });
      setTimeout(() => {
        try {
          element.removeChild(particle);
        } catch {
        }
      }, t);
    }, 30);
  }
};
const updateEffectPosition = (element) => {
  if (!containerRef.value || !filterRef.value || !textRef.value) return;
  const containerRect = containerRef.value.getBoundingClientRect();
  const pos = element.getBoundingClientRect();
  const styles = {
    left: `${pos.x - containerRect.x}px`,
    top: `${pos.y - containerRect.y}px`,
    width: `${pos.width}px`,
    height: `${pos.height}px`
  };
  Object.assign(filterRef.value.style, styles);
  Object.assign(textRef.value.style, styles);
  textRef.value.textContent = element.textContent;
};
const handleClick = (e, index) => {
  const liEl = e.currentTarget.parentElement;
  if (activeIndex.value === index) return;
  activeIndex.value = index;
  updateEffectPosition(liEl);
  if (filterRef.value) {
    const particles = filterRef.value.querySelectorAll(".particle");
    particles.forEach((p) => filterRef.value.removeChild(p));
  }
  if (textRef.value) {
    textRef.value.classList.remove("active");
    void textRef.value.offsetWidth;
    textRef.value.classList.add("active");
  }
  if (filterRef.value) {
    makeParticles(filterRef.value);
  }
};
const handleKeyDown = (e, index) => {
  if (e.key === "Enter" || e.key === " ") {
    e.preventDefault();
    const liEl = e.currentTarget.parentElement;
    if (liEl) {
      handleClick(
        {
          currentTarget: liEl
        },
        index
      );
    }
  }
};
watch(activeIndex, () => {
  if (!navRef.value || !containerRef.value) return;
  const activeLi = navRef.value.querySelectorAll("li")[activeIndex.value];
  if (activeLi) {
    updateEffectPosition(activeLi);
    textRef.value?.classList.add("active");
  }
});
onMounted(() => {
  if (!navRef.value || !containerRef.value) return;
  const activeLi = navRef.value.querySelectorAll("li")[activeIndex.value];
  if (activeLi) {
    updateEffectPosition(activeLi);
    textRef.value?.classList.add("active");
  }
  resizeObserver = new ResizeObserver(() => {
    const currentActiveLi = navRef.value?.querySelectorAll("li")[activeIndex.value];
    if (currentActiveLi) {
      updateEffectPosition(currentActiveLi);
    }
  });
  resizeObserver.observe(containerRef.value);
});
onUnmounted(() => {
  if (resizeObserver) {
    resizeObserver.disconnect();
  }
});
</script>

<style>
:root{--linear-ease:linear(0,0.068,0.19 2.7%,0.804 8.1%,1.037,1.199 13.2%,1.245,1.27 15.8%,1.274,1.272 17.4%,1.249 19.1%,0.996 28%,0.949,0.928 33.3%,0.926,0.933 36.8%,1.001 45.6%,1.013,1.019 50.8%,1.018 54.4%,1 63.1%,0.995 68%,1.001 85%,1)}.effect{display:grid;opacity:1;place-items:center;pointer-events:none;position:absolute;z-index:1}.effect.text{color:#fff;transition:color .3s ease}.effect.text.active{color:#000}.effect.filter{filter:blur(7px) contrast(100) blur(0);mix-blend-mode:lighten}.effect.filter:before{background:#000;content:"";inset:-75px;position:absolute;z-index:-2}.effect.filter:after{background:#fff;border-radius:9999px;content:"";inset:0;opacity:0;position:absolute;transform:scale(0);z-index:-1}.effect.active:after{animation:pill .3s ease both}@keyframes pill{to{opacity:1;transform:scale(1)}}.particle,.point{border-radius:9999px;display:block;height:20px;opacity:0;transform-origin:center;width:20px}.particle{--time:5s;animation:particle calc(var(--time)) ease 1 -.35s;left:calc(50% - 8px);position:absolute;top:calc(50% - 8px)}.point{animation:point calc(var(--time)) ease 1 -.35s;background:var(--color);opacity:1}@keyframes particle{0%{animation-timing-function:cubic-bezier(.55,0,1,.45);opacity:1;transform:rotate(0deg) translate(calc(var(--start-x)),calc(var(--start-y)))}70%{animation-timing-function:ease;opacity:1;transform:rotate(calc(var(--rotate)*.5)) translate(calc(var(--end-x)*1.2),calc(var(--end-y)*1.2))}85%{opacity:1;transform:rotate(calc(var(--rotate)*.66)) translate(calc(var(--end-x)),calc(var(--end-y)))}to{opacity:1;transform:rotate(calc(var(--rotate)*1.2)) translate(calc(var(--end-x)*.5),calc(var(--end-y)*.5))}}@keyframes point{0%{animation-timing-function:cubic-bezier(.55,0,1,.45);opacity:0;transform:scale(0)}25%{transform:scale(calc(var(--scale)*.25))}38%{opacity:1}65%{animation-timing-function:ease;opacity:1;transform:scale(var(--scale))}85%{opacity:1;transform:scale(var(--scale))}to{opacity:0;transform:scale(0)}}li.active{color:#000;text-shadow:none}li.active:after{opacity:1;transform:scale(1)}li:after{background:#fff;border-radius:8px;content:"";inset:0;opacity:0;position:absolute;transform:scale(0);transition:all .3s ease;z-index:-1}
</style>
